+      _features.clear_feature(CPU_AES);
+    }
+  } else if (UseAES) {
+    if (!FLAG_IS_DEFAULT(UseAES)) {
+      warning("AES instructions are not available on this CPU");
+    }
+    FLAG_SET_DEFAULT(UseAES, false);
+  }
+
+  if (supports_fma()) {
+    if (FLAG_IS_DEFAULT(UseFMA)) {
+      UseFMA = true;
