+    }
+  } else if (UseFMA) {
+    if (!FLAG_IS_DEFAULT(UseFMA)) {
+      warning("FMA instructions are not available on this CPU");
+    }
+    FLAG_SET_DEFAULT(UseFMA, false);
+  }
